import './Testimonials.css'
import Slider from 'react-slick'
import { FaChevronLeft, FaChevronRight } from 'react-icons/fa'

const testimonials = [
    {
        img: '/photos/olena.png',
        text: '"mWallet допоміг мені побачити справжній стан бюджету"',
        author: 'Олена, 27 років'
    },
    {
        img: '/photos/olena.png',
        text: '"Я вперше реально контролюю свої витрати!"',
        author: 'Олена, 27 років'
    },
    {
        img: '/photos/olena.png',
        text: '"Найзручніший застосунок для мого бюджету"',
        author: 'Олена, 27 років'
    },
    {
        img: '/photos/olena.png',
        text: '"Все стало прозоро і просто"',
        author: 'Олена, 27 років'
    },
    {
        img: '/photos/olena.png',
        text: '"Я тепер знаю, куди йдуть мої гроші"',
        author: 'Олена, 27 років'
    },
    {
        img: '/photos/olena.png',
        text: '"mWallet — мастхев для кожного!"',
        author: 'Олена, 27 років'
    },
]

const Arrow = ({ className, onClick, icon }) => (
    <div className={`custom-arrow ${className}`} onClick={onClick}>
        {icon}
    </div>
)

const Testimonials = () => {
    const settings = {
        dots: false,
        infinite: true,
        speed: 500,
        slidesToShow: 2,
        slidesToScroll: 1,
        nextArrow: <Arrow icon={<FaChevronRight />} />,
        prevArrow: <Arrow icon={<FaChevronLeft />} />,
        responsive: [
            {
                breakpoint: 768,
                settings: { slidesToShow: 1 }
            }
        ]
    }

    return (
        <section className="testimonials" id="testimonials">
            <h2>Що кажуть про нас</h2>

            <Slider {...settings} className="testimonials-slider">
                {testimonials.map((t, index) => (
                    <div key={index} className="testimonial-card">
                        <img src={t.img} alt="Олена" className="avatar" />
                        <p className="quote">{t.text}</p>
                        <p className="author">{t.author}</p>
                    </div>
                ))}
            </Slider>

            <div className="partners">
                <img src="/photos/trustly.png" alt="Trustly logo" className="trustly" />
                <img src="/photos/visa.svg" alt="Visa logo" />
                <img src="/photos/gpay.svg" alt="Google Pay logo" />
            </div>
        </section>
    )
}

export default Testimonials
